import BaseLayout from './BaseLayout.astro';
import TopBar from '../components/TopBar.astro';

interface Props {
  name: string;
  back?: boolean;
  wide?: boolean;
  description?: string;
}

const { name, back = false, wide = false, description } = Astro.props;
const title = name === 'incomplete.fun' ? name : `${name} - incomplete.fun`;
---

<BaseLayout title={title} description={description}>
  <div class="app-shell">
