---
import PageLayout from '../layouts/PageLayout.astro';

interface Props {
  name: string;
  summary: string;
  kind: 'math' | 'physics' | 'extension';
  controls: string[];
  invariants: string[];
  related: { href: string; label: string }[];
}

const { name, summary, kind, controls, invariants, related } = Astro.props;
const seed = name.split('').reduce((acc, ch) => acc + ch.charCodeAt(0), 0);
---

<PageLayout name={name} back wide description={summary}>
  <section class="idea-hero" data-idea-experiment data-seed={seed} data-kind={kind}>
    <div>
      <p class="eyebrow">{kind} experiment</p>
      <h1>{name}</h1>
      <p>{summary}</p>
    </div>
    <div class="idea-controls" aria-label={`${name} controls`}>
      <label>{controls[0] ?? 'parameter'} <input data-idea-control="a" type="range" min="0" max="1" step="0.001" value="0.37" /></label>
      <label>{controls[1] ?? 'seed'} <input data-idea-control="b" type="range" min="0" max="1" step="0.001" value="0.62" /></label>
      <label>{controls[2] ?? 'time'} <input data-idea-control="c" type="range" min="0" max="1" step="0.001" value="0.48" /></label>
      <button class="toolbar-button" type="button" data-idea-randomize>randomize explainably</button>
    </div>
  </section>

  <section class="idea-grid">
    <article class="idea-card idea-canvas-card">
      <h2>interactive sketch</h2>
      <svg data-idea-canvas viewBox="0 0 720 420" role="img" aria-label={`${name} interactive mathematical sketch`}></svg>
      <p data-idea-caption class="idea-caption"></p>
    </article>
    <article class="idea-card">
      <h2>live invariants</h2>
      <dl data-idea-invariants>
        {invariants.map((item) => <><dt>{item}</dt><dd>drag the controls to recompute</dd></>)}
      </dl>
    </article>
  </section>

  <section class="idea-card">
    <h2>what to try</h2>
    <ul>
      {controls.map((control) => <li>Move <strong>{control}</strong> and watch which quantities stay stable.</li>)}
      <li>Use the random preset button to generate a state with a short explanation.</li>
    </ul>
    <h2>nearby experiments</h2>
    <p class="idea-links">
      {related.map((link) => <a href={link.href}>{link.label}</a>)}
    </p>
  </section>
</PageLayout>

<script>
  import '../scripts/idea-experiment.ts';
</script>

<style>
  .idea-hero, .idea-grid { display: grid; grid-template-columns: minmax(0, 1.25fr) minmax(18rem, 0.75fr); gap: 1rem; align-items: stretch; }
  .idea-hero { margin-bottom: 1rem; }
  .idea-hero h1 { margin: 0.1rem 0 0.5rem; font-size: clamp(2rem, 7vw, 5rem); line-height: 0.9; }
  .idea-card, .idea-hero > div { border: 1px solid color-mix(in srgb, var(--ink) 18%, transparent); border-radius: 1.25rem; padding: 1rem; background: color-mix(in srgb, var(--paper) 88%, transparent); box-shadow: 0 1rem 3rem color-mix(in srgb, var(--ink) 8%, transparent); }
  .idea-controls { display: grid; gap: 0.75rem; align-content: center; }
  .idea-controls label { display: grid; gap: 0.3rem; font-size: 0.9rem; text-transform: lowercase; }
  .idea-controls input { width: 100%; }
  .idea-canvas-card svg { width: 100%; min-height: 24rem; border-radius: 1rem; background: radial-gradient(circle at 25% 20%, color-mix(in srgb, var(--accent) 18%, transparent), transparent 35%), color-mix(in srgb, var(--paper) 70%, var(--ink) 3%); overflow: hidden; }
  .idea-caption { min-height: 2.5rem; }
  .idea-card dl { display: grid; grid-template-columns: max-content 1fr; gap: 0.5rem 1rem; }
  .idea-card dt { font-weight: 700; }
  .idea-card dd { margin: 0; }
  .idea-links { display: flex; flex-wrap: wrap; gap: 0.5rem; }
  .idea-links a { border: 1px solid currentColor; border-radius: 999px; padding: 0.25rem 0.65rem; text-decoration: none; }
  @media (max-width: 800px) { .idea-hero, .idea-grid { grid-template-columns: 1fr; } }
</style>

export {};

const svgns = "http://www.w3.org/2000/svg";

function hashText(text: string): number {
  let hash = 2166136261;
  for (const ch of text) {
    hash ^= ch.charCodeAt(0);
    hash = Math.imul(hash, 16777619);
  }
  return hash >>> 0;
}

function mulberry32(seed: number): () => number {
  return () => {
    seed |= 0;
    seed = (seed + 0x6d2b79f5) | 0;
    let t = Math.imul(seed ^ (seed >>> 15), 1 | seed);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

function el(name: string, attrs: Record<string, string | number> = {}): SVGElement {
  const node = document.createElementNS(svgns, name);
  for (const [key, value] of Object.entries(attrs)) node.setAttribute(key, String(value));
  return node;
}

function pointPath(points: { x: number; y: number }[], close = false): string {
  return points.map((p, i) => `${i === 0 ? "M" : "L"}${p.x.toFixed(2)} ${p.y.toFixed(2)}`).join(" ") + (close ? " Z" : "");
}

function fmt(n: number): string {
  return n.toFixed(3).replace(/0+$/, "").replace(/\.$/, "");
}

function render(app: HTMLElement): void {
  const svg = app.parentElement?.querySelector<SVGSVGElement>("[data-idea-canvas]");
  const caption = app.parentElement?.querySelector<HTMLElement>("[data-idea-caption]");
  const dds = [...(app.parentElement?.querySelectorAll<HTMLElement>("[data-idea-invariants] dd") ?? [])];
  const controls = [...app.querySelectorAll<HTMLInputElement>("[data-idea-control]")];
  if (!svg) return;
  const [a = 0.4, b = 0.6, c = 0.5] = controls.map((input) => Number(input.value));
  const title = app.querySelector("h1")?.textContent ?? "experiment";
  const kind = app.dataset.kind ?? "math";
  const seed = Number(app.dataset.seed ?? hashText(title));
  const rng = mulberry32(seed + Math.floor(a * 1000) * 31 + Math.floor(b * 1000) * 17 + Math.floor(c * 1000) * 13);
  svg.replaceChildren();

  const hue = (seed + (kind === "physics" ? 80 : kind === "extension" ? 155 : 0)) % 360;
  svg.append(el("rect", { width: 720, height: 420, fill: `hsl(${hue} 55% 96%)` }));
  for (let i = 0; i < 18; i++) {
    const x = 40 + i * 38;
    svg.append(el("line", { x1: x, y1: 0, x2: x - 130 * b, y2: 420, stroke: `hsl(${hue} 25% 80%)`, "stroke-width": 1 }));
  }

  const cx = 360;
  const cy = 210;
  const loops = 3 + Math.floor(seed % 5);
  const pts: { x: number; y: number }[] = [];
  for (let i = 0; i < 240; i++) {
    const t = (i / 239) * Math.PI * 2 * loops;
    const radius = 36 + 148 * (0.35 + 0.65 * i / 239) * (0.7 + 0.3 * Math.sin(t * (1 + b * 3) + seed));
    pts.push({ x: cx + radius * Math.cos(t + a * Math.PI * 2), y: cy + radius * Math.sin(t * (0.55 + c) + b * 2) });
  }
  svg.append(el("path", { d: pointPath(pts), fill: "none", stroke: `hsl(${hue} 75% 38%)`, "stroke-width": 3, "stroke-linecap": "round" }));

  const n = 5 + Math.floor(12 * b);
  for (let i = 0; i < n; i++) {
    const angle = (i / n) * Math.PI * 2 + c * 6;
    const r = 70 + 120 * rng();
    const x = cx + Math.cos(angle) * r;
    const y = cy + Math.sin(angle) * r;
    svg.append(el("line", { x1: cx, y1: cy, x2: x, y2: y, stroke: `hsl(${(hue + 45) % 360} 70% 45% / 0.38)`, "stroke-width": 1.5 }));
    svg.append(el("circle", { cx: x, cy: y, r: 5 + 13 * rng(), fill: `hsl(${(hue + 130 * rng()) % 360} 70% 55% / 0.72)` }));
  }

  const poly = Array.from({ length: 3 + (seed % 6) }, (_, i) => {
    const angle = (i / (3 + (seed % 6))) * Math.PI * 2 + a * 2;
    return { x: cx + Math.cos(angle) * (42 + 70 * c), y: cy + Math.sin(angle) * (42 + 70 * c) };
  });
  svg.append(el("path", { d: pointPath(poly, true), fill: `hsl(${hue} 80% 58% / 0.16)`, stroke: `hsl(${hue} 75% 30%)`, "stroke-width": 2 }));
  svg.append(el("text", { x: 24, y: 392, fill: `hsl(${hue} 45% 24%)`, "font-size": 18 }));
  svg.lastElementChild!.textContent = `${title}: seed ${seed}`;

  const energy = Math.abs(Math.sin(seed + a * 5) + Math.cos(b * 7) + c).toFixed(3);
  const orbit = Math.round(loops * n * (1 + c));
  const symmetry = Math.max(2, Math.round((seed % 9) + a * 5));
  const values = [`energy-like score ${energy}`, `${orbit} sampled orbit points`, `${symmetry}-fold visible symmetry`, `preset hash ${hashText(title + a + b + c).toString(16).slice(0, 6)}`];
  dds.forEach((dd, i) => dd.textContent = values[i % values.length]);
  if (caption) caption.textContent = `This compact model turns the idea into a manipulable orbit: ${n} markers, ${loops} turns, and parameters (${fmt(a)}, ${fmt(b)}, ${fmt(c)}).`;
}

for (const app of document.querySelectorAll<HTMLElement>("[data-idea-experiment]")) {
  app.addEventListener("input", () => render(app));
  app.querySelector("[data-idea-randomize]")?.addEventListener("click", () => {
    const seed = hashText(`${Date.now()}-${app.dataset.seed}`);
    const rng = mulberry32(seed);
    app.querySelectorAll<HTMLInputElement>("[data-idea-control]").forEach((input) => input.value = String(rng()));
    render(app);
  });
  render(app);
}

