---
import PageLayout from '../layouts/PageLayout.astro';
import { experiments } from '../data/experiments';
---

<PageLayout name="incomplete.fun" description="Small mathematical experiments, intentionally incomplete.">
  <section class="home-hero">
    <canvas class="landing-animation" data-landing-animation aria-hidden="true"></canvas>
    <p class="eyebrow">small experiments</p>
    <h1>mathematical toys, kept intentionally incomplete.</h1>
    <p class="home-intro">A quiet collection of visual calculators and playgrounds. Pick a thread and pull.</p>
  </section>

  <section class="constellation-map" aria-label="Experiment map">
    <svg viewBox="0 0 100 34" role="img">
      <title>Constellation map of experiments</title>
      {experiments.map((_, index) => {
        const x = 8 + (index % 8) * 12;
        const y = 6 + Math.floor(index / 8) * 11 + (index % 2) * 2;
        const nx = 8 + ((index + 1) % 8) * 12;
        const ny = 6 + Math.floor((index + 1) / 8) * 11 + ((index + 1) % 2) * 2;
        return <><line x1={x} y1={y} x2={nx} y2={ny} /><circle cx={x} cy={y} r="1.2" /></>;
      })}
    </svg>
  </section>

  <nav class="home-links" aria-label="Experiments">
    {experiments.map((experiment) => (
      <a class="home-link" href={experiment.href}>
        <canvas class="home-preview" data-preview-canvas={experiment.href} aria-hidden="true"></canvas>
        <span>{experiment.title}</span>
        <small>{experiment.summary}</small>
      </a>
    ))}
  </nav>
</PageLayout>

<script>
  import '../scripts/gallery-previews.ts';
  import '../scripts/landing-animation.ts';
</script>

:root {
  --bg: #fcfcfa;
  --fg: #171716;
  --muted: #716f68;
  --line: #e4e1d8;
  --wash: color-mix(in srgb, var(--bg) 94%, var(--fg));
  --accent: currentColor;
  --border: var(--line);
  --mono: inherit;
  --space: clamp(1rem, 4vw, 2.5rem);
  --measure: 38rem;
  font-family: ui-monospace, "SFMono-Regular", Menlo, Consolas, monospace;
}

* { box-sizing: border-box; }

body {
  margin: 0;
  background: var(--bg);
  color: var(--fg);
  font-size: 15px;
  line-height: 1.65;
  text-rendering: optimizeLegibility;
}

a {
  color: inherit;
  text-decoration: underline;
  text-decoration-color: var(--line);
  text-underline-offset: .25em;
}

a:hover { text-decoration-color: currentColor; }

h1, h2, h3, p, ul, ol { margin: 0 0 1rem; }

h1, h2, h3, strong { font-weight: 600; }

h1 {
  max-width: 13ch;
  font-size: clamp(2rem, 9vw, 5rem);
  line-height: .95;
  letter-spacing: -0.06em;
}

ul, ol { padding-left: 1.25rem; }

code {
  padding: .1em .3em;
  border: 1px solid var(--line);
  border-radius: 3px;
}

.app-shell, .canvas-app {
  min-height: 100dvh;
  background: var(--bg);
}

.app-shell { display: grid; grid-template-rows: auto 1fr; }
.canvas-app {
  position: relative;
  display: flex;
  flex-direction: column;
}

.equation-wallpaper {
  position: fixed;
  inset: 0;
  z-index: 0;
  overflow: hidden;
  pointer-events: none;
  color: var(--fg);
  opacity: .065;
}

.equation-wallpaper span {
  position: absolute;
  animation: equation-drift linear infinite;
  white-space: nowrap;
}

.canvas-app > :not(.equation-wallpaper) {
  position: relative;
  z-index: 1;
}

@keyframes equation-drift {
  from { transform: translate3d(-1rem, 0, 0) rotate(-6deg); }
  to { transform: translate3d(1rem, -4rem, 0) rotate(6deg); }
}

.control-panel {
  display: flex;
  align-items: center;
  gap: .6rem;
  padding: .55rem var(--space);
  border-bottom: 1px solid var(--line);
  background: color-mix(in srgb, var(--bg) 88%, transparent);
  backdrop-filter: blur(10px);
  flex-wrap: wrap;
}

.control-panel input[type="range"] { width: 8rem; }

.is-darkroom .canvas-app {
  background: #020202;
  color: #f5f2e8;
}

.is-darkroom .topbar,
.is-darkroom .control-panel {
  opacity: .08;
  transition: opacity .6s ease;
}

.is-darkroom .topbar:hover,
.is-darkroom .control-panel:hover { opacity: 1; }

.is-darkroom .canvas-stage::after {
  content: attr(id);
  position: absolute;
  left: var(--space);
  bottom: var(--space);
  color: currentColor;
  opacity: .35;
  animation: darkroom-label 3s ease both;
  pointer-events: none;
}

@keyframes darkroom-label { from { opacity: 0; transform: translateY(.5rem); } }

.topbar {
  display: flex;
  align-items: center;
  gap: 1rem;
  min-height: 3.25rem;
  padding: .75rem var(--space);
  border-bottom: 1px solid var(--line);
  flex-wrap: wrap;
}

.brand,
.topbar-title {
  text-decoration: none;
}

.brand { font-weight: 600; }

.topbar-title { color: var(--muted); }

.back-link {
  color: var(--muted);
  text-decoration: none;
}

.page {
  width: min(100%, var(--measure));
  margin: 0 auto;
  padding: calc(var(--space) * 1.4) var(--space);
}

.page-wide { --measure: 72rem; }

.home-hero {
  position: relative;
  display: grid;
  gap: 1rem;
  margin-bottom: calc(var(--space) * 1.3);
  padding: min(8vw, 4rem) 0;
}

.landing-animation {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  z-index: 0;
  opacity: .55;
}

.home-hero > :not(.landing-animation) {
  position: relative;
  z-index: 1;
}

.eyebrow,
.home-intro { color: var(--muted); }

.eyebrow {
  margin: 0;
  font-size: .78rem;
  letter-spacing: .08em;
  text-transform: uppercase;
}

.constellation-map {
  margin-bottom: calc(var(--space) * 1.2);
  border: 1px solid var(--line);
  border-radius: 18px;
  padding: .75rem;
  background: var(--wash);
}

.constellation-map svg {
  display: block;
  width: 100%;
  height: auto;
  overflow: visible;
}

.constellation-map line {
  stroke: var(--fg);
  stroke-width: .15;
  opacity: .2;
  stroke-dasharray: 1 1.5;
  animation: map-pulse 6s linear infinite;
}

.constellation-map circle {
  fill: var(--fg);
  opacity: .6;
}

@keyframes map-pulse { to { stroke-dashoffset: -10; } }

.home-links {
  display: grid;
  gap: .5rem;
}

.home-link {
  display: grid;
  grid-template-columns: 5rem minmax(0, 1fr) minmax(8rem, 14rem);
  align-items: center;
  gap: 1rem;
  padding: .8rem 0;
  border-top: 1px solid var(--line);
  text-decoration: none;
}


