  svg.append(el("line", { x1: a.x, y1: a.y, x2: b.x, y2: b.y, ...attrs }));
}

function circle(svg: SVGSVGElement, p: Point, r: number, attrs: Record<string, string | number> = {}): void {
  svg.append(el("circle", { cx: p.x, cy: p.y, r, ...attrs }));
}

