  }

  if (slug === "relativity-diagram") {
    line(svg, { x: 360, y: 360 }, { x: 360, y: 40 }, { stroke }); line(svg, { x: 80, y: 210 }, { x: 650, y: 210 }, { stroke });
    line(svg, { x: 210, y: 360 }, { x: 510, y: 60 }, { stroke: faint }); line(svg, { x: 510, y: 360 }, { x: 210, y: 60 }, { stroke: faint });
